                }

            }

            l >>= 1; r >>= 1;

        }

        while (nl >>= 1)node[nl] = nodef(node[2 * nl], node[2 * nl + 1]);

        while (nr >>= 1)node[nr] = nodef(node[2 * nr], node[2 * nr + 1]);

