        l += n; r += n;

        T ls = nodee, rs = nodee;

        while (l < r) {

            if (l & 1) {

                ls = nodef(ls, node[l]);

                l++;

            }

            if (r & 1) {

                r--;

                rs = nodef(node[r], rs);

            }

            l >>= 1; r >>= 1;

        }

        return nodef(ls, rs);

    }

    virtual T operator[](const int& x) {

        return node[n + x];

    }

    void fill(T x) {

        std::fill(ALL(node), x);

    }

    void print() {

        rep(i, n)std::cout << operator[](i) << " ";

        std::cout << std::endl;

    }

};

