#include "bits/stdc++.h"

using namespace std;

#define ll long long int

#define rep(i,n) for( int i = 0; i < n; i++ )

#define rrep(i,n) for( int i = n; i >= 0; i-- )

#define REP(i,s,t) for( int i = s; i <= t; i++ )

#define RREP(i,s,t) for( int i = s; i >= t; i-- )

#define dump(x)  cerr << #x << " = " << (x) << endl;

#define INF 2000000000

#define mod 1000000007

#define INF2 100000000000000000

#define int long long

int ans[2][100010];

typedef pair<int, int> P;

typedef pair<int, P> PP;

vector<PP> G[100010];





void dijkstra(int s, int kind) {

    priority_queue<P, vector<P>, greater<P> > que;

    rep(j, 100010) ans[kind][j] = INF2;

    ans[kind][s] = 0;

    que.push(P(0, s));



    while (!que.empty()) {

        P p = que.top(); que.pop();

        int v = p.second;

        if (ans[kind][v] < p.first) continue;

        for (int i = 0; i < G[v].size(); i++){

            P e;

            e.first = G[v][i].first;

            if (kind == 0) e.second= G[v][i].second.first;

            else e.second = G[v][i].second.second;

            if (ans[kind][e.first] > ans[kind][v] + e.second) {

                ans[kind][e.first] = ans[kind][v] + e.second;

                que.push(P(ans[kind][e.first], e.first));

            }

        }

    }

}



signed main(void)

{

    cin.tie(0);

    ios::sync_with_stdio(false);

    int n, m, s, t; cin >> n >> m >> s >> t;

    s--; t--;

    rep(i, m) {

        int u, v, a, b;

        cin >> u >> v >> a >> b;

        u--; v--;

        G[u].push_back({v, {a, b}});

        G[v].push_back({u, {a, b}});

    }

    dijkstra(s, 0);

    dijkstra(t, 1);



    int k = INF2;

    vector<int> output;

    rrep(i, n - 1) {

        k = min(k, ans[0][i] + ans[1][i]);

        output.push_back(1000000000000000 - k);

    }

    rrep(i, n - 1) cout << output[i] << endl;





    return 0;

}

